// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>

// Define the structure for a binary tree node
typedef struct Node {
    int data;
    struct Node* left;
    struct Node* right;
} Node;

// Function to create a new binary tree node
Node* createNode(int data) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    if (!newNode) {
        printf("Memory error
");
        return NULL;
    }
    newNode->data = data;
    newNode->left = newNode->right = NULL;
    return newNode;
}

// Function to perform in-order traversal
void inOrder(Node* root, int* result, int* index) {
    if (root) {
        inOrder(root->left, result, index);
        result[(*index)++] = root->data;
        inOrder(root->right, result, index);
    }
}

// Function to perform pre-order traversal
void preOrder(Node* root, int* result, int* index) {
    if (root) {
        result[(*index)++] = root->data;
        preOrder(root->left, result, index);
        preOrder(root->right, result, index);
    }
}

// Function to perform post-order traversal
void postOrder(Node* root, int* result, int* index) {
    if (root) {
        postOrder(root->left, result, index);
        postOrder(root->right, result, index);
        result[(*index)++] = root->data;
    }
}

// Function to get the traversals
void getTraversals(Node* root, int* inOrderResult, int* preOrderResult, int* postOrderResult) {
    int inOrderIndex = 0;
    int preOrderIndex = 0;
    int postOrderIndex = 0;
    inOrder(root, inOrderResult, &inOrderIndex);
    preOrder(root, preOrderResult, &preOrderIndex);
    postOrder(root, postOrderResult, &postOrderIndex);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int* levelOrder = (int*) malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &levelOrder[i]);
        }
        Node* root = NULL;
        // Create the binary tree from the level order traversal
        root = createNode(levelOrder[0]);
        int queueIndex = 0;
        Node** queue = (Node**) malloc(N * sizeof(Node*));
        queue[queueIndex++] = root;
        int i = 1;
        while (i < N && queueIndex > 0) {
            Node* currentNode = queue[0];
            queueIndex--;
            if (levelOrder[i] != -1) {
                currentNode->left = createNode(levelOrder[i]);
                queue[queueIndex++] = currentNode->left;
            }
            i++;
            if (i < N && levelOrder[i] != -1) {
                currentNode->right = createNode(levelOrder[i]);
                queue[queueIndex++] = currentNode->right;
            }
            i++;
        }
        free(queue);
        int* inOrderResult = (int*) malloc(N * sizeof(int));
        int* preOrderResult = (int*) malloc(N * sizeof(int));
        int* postOrderResult = (int*) malloc(N * sizeof(int));
        getTraversals(root, inOrderResult, preOrderResult, postOrderResult);
        // Print the traversals
        printf("[");
        printf("[");
        for (int i = 0; i < N; i++) {
            if (inOrderResult[i] != 0) {
                printf("%d", inOrderResult[i]);
                if (i < N - 1 && inOrderResult[i + 1] != 0) {
                    printf(", ");
                }
            }
        }
        printf("], [");
        for (int i = 0; i < N; i++) {
            if (preOrderResult[i] != 0) {
                printf("%d", preOrderResult[i]);
                if (i < N - 1 && preOrderResult[i + 1] != 0) {
                    printf(", ");
                }
            }
        }
        printf("], [");
        for (int i = 0; i < N; i++) {
            if (postOrderResult[i] != 0) {
                printf("%d", postOrderResult[i]);
                if (i < N - 1 && postOrderResult[i + 1] != 0) {
                    printf(", ");
                }
            }
        }
        printf("]]
");
        free(inOrderResult);
        free(preOrderResult);
        free(postOrderResult);
        free(levelOrder);
    }
    return 0;
}

