// COMPLETE, COMPILABLE C++ code
#include <iostream>
#include <vector>
using namespace std;

// Define the structure for a binary tree node
struct Node {
    int data;
    Node* left;
    Node* right;
};

// Function to create a new binary tree node
Node* createNode(int data) {
    Node* newNode = new Node();
    newNode->data = data;
    newNode->left = newNode->right = NULL;
    return newNode;
}

// Function to perform in-order traversal
void inOrder(Node* root, vector<int>& result) {
    if (root) {
        inOrder(root->left, result);
        result.push_back(root->data);
        inOrder(root->right, result);
    }
}

// Function to perform pre-order traversal
void preOrder(Node* root, vector<int>& result) {
    if (root) {
        result.push_back(root->data);
        preOrder(root->left, result);
        preOrder(root->right, result);
    }
}

// Function to perform post-order traversal
void postOrder(Node* root, vector<int>& result) {
    if (root) {
        postOrder(root->left, result);
        postOrder(root->right, result);
        result.push_back(root->data);
    }
}

// Function to get the traversals
void getTraversals(Node* root, vector<int>& inOrderResult, vector<int>& preOrderResult, vector<int>& postOrderResult) {
    inOrder(root, inOrderResult);
    preOrder(root, preOrderResult);
    postOrder(root, postOrderResult);
}

int main() {
    int T;
    cin >> T;
    while (T--) {
        int N;
        cin >> N;
        vector<int> levelOrder(N);
        for (int i = 0; i < N; i++) {
            cin >> levelOrder[i];
        }
        Node* root = NULL;
        // Create the binary tree from the level order traversal
        root = createNode(levelOrder[0]);
        int queueIndex = 0;
        Node** queue = new Node*[N];
        queue[queueIndex++] = root;
        int i = 1;
        while (i < N && queueIndex > 0) {
            Node* currentNode = queue[0];
            queueIndex--;
            if (levelOrder[i] != -1) {
                currentNode->left = createNode(levelOrder[i]);
                queue[queueIndex++] = currentNode->left;
            }
            i++;
            if (i < N && levelOrder[i] != -1) {
                currentNode->right = createNode(levelOrder[i]);
                queue[queueIndex++] = currentNode->right;
            }
            i++;
        }
        delete[] queue;
        vector<int> inOrderResult;
        vector<int> preOrderResult;
        vector<int> postOrderResult;
        getTraversals(root, inOrderResult, preOrderResult, postOrderResult);
        // Print the traversals
        cout << "[";
        cout << "[";
        for (int i = 0; i < inOrderResult.size(); i++) {
            cout << inOrderResult[i];
            if (i < inOrderResult.size() - 1) {
                cout << ", ";
            }
        }
        cout << "], [";
        for (int i = 0; i < preOrderResult.size(); i++) {
            cout << preOrderResult[i];
            if (i < preOrderResult.size() - 1) {
                cout << ", ";
            }
        }
        cout << "], [";
        for (int i = 0; i < postOrderResult.size(); i++) {
            cout << postOrderResult[i];
            if (i < postOrderResult.size() - 1) {
                cout << ", ";
            }
        }
        cout << "]]
";
    }
    return 0;
}

